   637→
   638→void ConnPoolImplBase::purgePendingStreams(
   639→    const Upstream::HostDescriptionConstSharedPtr& host_description,
   640→    absl::string_view failure_reason, ConnectionPool::PoolFailureReason reason) {
   641→  // NOTE: We move the existing pending streams to a temporary list. This is done so that
   642→  //       if retry logic submits a new stream to the pool, we don't fail it inline.
   643→  state_.decrPendingStreams(pending_streams_.size());
   644→  pending_streams_to_purge_ = std::move(pending_streams_);
   645→  while (!pending_streams_to_purge_.empty()) {
   646→    PendingStreamPtr stream =
   647→        pending_streams_to_purge_.front()->removeFromList(pending_streams_to_purge_);
   648→    host_->cluster().trafficStats()->upstream_rq_pending_failure_eject_.inc();
   649→    onPoolFailure(host_description, failure_reason, reason, stream->context());
   650→  }
   651→}
   652→
   653→bool ConnPoolImplBase::connectingConnectionIsExcess(const ActiveClient& client) const {
   654→  ASSERT(!client.hasHandshakeCompleted());
   655→  ASSERT(connecting_stream_capacity_ >= client.currentUnusedCapacity());
   656→  // If perUpstreamPreconnectRatio is one, this simplifies to checking if there would still be
   657→  // sufficient connecting stream capacity to serve all pending streams if the most recent client
   658→  // were removed from the picture.
   659→  //
   660→  // If preconnect ratio is set, it also factors in the anticipated load based on both queued
   661→  // streams and active streams, and makes sure the connecting capacity would still be sufficient to
   662→  // serve that even with the most recent client removed.
   663→  return (pending_streams_.size() + num_active_streams_) * perUpstreamPreconnectRatio() <=
   664→         (connecting_stream_capacity_ - client.currentUnusedCapacity() + num_active_streams_);
   665→}
   666→
   667→void ConnPoolImplBase::onPendingStreamCancel(PendingStream& stream,
   668→                                             Envoy::ConnectionPool::CancelPolicy policy) {
   669→  ENVOY_LOG(debug, "cancelling pending stream");
   670→  if (!pending_streams_to_purge_.empty()) {
   671→    // If pending_streams_to_purge_ is not empty, it means that we are called from
   672→    // with-in a onPoolFailure callback invoked in purgePendingStreams (i.e. purgePendingStreams
   673→    // is down in the call stack). Remove this stream from the list as it is cancelled,
   674→    // and there is no need to call its onPoolFailure callback.
   675→    stream.removeFromList(pending_streams_to_purge_);
   676→  } else {
   677→    state_.decrPendingStreams(1);
   678→    stream.removeFromList(pending_streams_);
   679→  }
   680→  if (policy == Envoy::ConnectionPool::CancelPolicy::CloseExcess) {
   681→    if (!connecting_clients_.empty() &&
   682→        connectingConnectionIsExcess(*connecting_clients_.front())) {
   683→      auto& client = *connecting_clients_.front();
   684→      transitionActiveClientState(client, ActiveClient::State::Draining);
   685→      client.close();
   686→    } else if (!early_data_clients_.empty()) {
   687→      for (ActiveClientPtr& client : early_data_clients_) {
   688→        if (client->numActiveStreams() == 0) {
   689→          // Find an idle early data client and check if it is excess.
   690→          if (connectingConnectionIsExcess(*client)) {
   691→            // Close the client after the for loop avoid messing up with iterator.
   692→            transitionActiveClientState(*client, ActiveClient::State::Draining);
   693→            client->close();
   694→          }
   695→          break;
   696→        }
   697→      }
   698→    }
   699→  }
   700→
   701→  host_->cluster().trafficStats()->upstream_rq_cancelled_.inc();
   702→  checkForIdleAndCloseIdleConnsIfDraining();
   703→}
   704→
   705→void ConnPoolImplBase::decrConnectingAndConnectedStreamCapacity(uint32_t delta,
   706→                                                                ActiveClient& client) {
   707→  state_.decrConnectingAndConnectedStreamCapacity(delta);
   708→  if (!client.hasHandshakeCompleted()) {
   709→    // If still doing handshake, it is contributing to the local connecting stream capacity. Update
   710→    // the capacity as well.
   711→    ASSERT(connecting_stream_capacity_ >= delta);
   712→    connecting_stream_capacity_ -= delta;
   713→  }
   714→}
   715→
   716→void ConnPoolImplBase::incrConnectingAndConnectedStreamCapacity(uint32_t delta,
   717→                                                                ActiveClient& client) {
   718→  state_.incrConnectingAndConnectedStreamCapacity(delta);
   719→  if (!client.hasHandshakeCompleted()) {
   720→    connecting_stream_capacity_ += delta;
   721→  }
   722→}
   723→
   724→void ConnPoolImplBase::onUpstreamReadyForEarlyData(ActiveClient& client) {
   725→  ASSERT(!client.hasHandshakeCompleted() && client.readyForStream());
   726→  // Check pending streams backward for safe request.
   727→  // Note that this is a O(n) search, but the expected size of pending_streams_ should be small. If
   728→  // this becomes a problem, we could split pending_streams_ into 2 lists.
   729→  auto it = pending_streams_.end();
   730→  if (it == pending_streams_.begin()) {
   731→    return;
   732→  }
   733→  --it;
   734→  while (client.currentUnusedCapacity() > 0) {
   735→    PendingStream& stream = **it;
   736→    bool stop_iteration{false};
   737→    if (it != pending_streams_.begin()) {
   738→      --it;
   739→    } else {
   740→      stop_iteration = true;
   741→    }
   742→
   743→    if (stream.can_send_early_data_) {
   744→      ENVOY_CONN_LOG(debug, "creating stream for early data.", client);
   745→      attachStreamToClient(client, stream.context());
   746→      state_.decrPendingStreams(1);
   747→      stream.removeFromList(pending_streams_);
   748→    }
   749→    if (stop_iteration) {
   750→      return;
   751→    }
   752→  }
   753→}
