   188→MultiplexedActiveClientBase::MultiplexedActiveClientBase(
   189→    HttpConnPoolImplBase& parent, uint32_t effective_concurrent_streams,
   190→    uint32_t max_configured_concurrent_streams, Stats::Counter& cx_total,
   191→    OptRef<Upstream::Host::CreateConnectionData> data)
   192→    : Envoy::Http::ActiveClient(
   193→          parent, maxStreamsPerConnection(parent.host()->cluster().maxRequestsPerConnection()),
   194→          effective_concurrent_streams, max_configured_concurrent_streams, data) {
   195→  codec_client_->setCodecClientCallbacks(*this);
   196→  codec_client_->setCodecConnectionCallbacks(*this);
   197→  cx_total.inc();
   198→}
   199→
   200→bool MultiplexedActiveClientBase::closingWithIncompleteStream() const {
   201→  return closed_with_active_rq_;
   202→}
   203→
   204→RequestEncoder& MultiplexedActiveClientBase::newStreamEncoder(ResponseDecoder& response_decoder) {
   205→  return codec_client_->newStream(response_decoder);
   206→}
